            slopeMap := make(map[string]int64)
            for k := 0; k < n; k++ {
                if k == i || k == j {
                    continue
                }
                // Check if point k is on a line parallel to (i,j)
                // The condition is (yj - yi)(xk - xi) == (yk - yi)(xj - xi)
                // Which means the slope from i to j is same as i to k
                // But to avoid division, we cross multiply
                dx1 := points[j][0] - points[i][0]
                dy1 := points[j][1] - points[i][1]
                dx2 := points[k][0] - points[i][0]
                dy2 := points[k][1] - points[i][1]

                if dx1*dy2 == dy1*dx2 {
                    // Points i, j, k are colinear, skip to avoid counting as parallel
                    continue
                }

                // Now find the slope of line (i,k) and check if it's parallel to (i,j)
                // Slope of (i,j): dy1/dx1
                // Slope of (i,k): dy2/dx2
                // Parallel if dy1*dx2 == dy2*dx1
                // But we already handled colinear case above
                // So now we need to find if there's another pair (l) such that (i,l) is parallel to (k,l)
                // Or any other combination
                // To generalize, we can group lines by their slope

                // To represent slope as a key in the map, we use reduced form (dx, dy)
                g := gcd(dx2, dy2)
                if g != 0 {
                    dx2 /= g
                    dy2 /= g
