                    if dx2 < 0 || (dx2 == 0 && dy2 < 0) {
                        dx2 = -dx2
                        dy2 = -dy2
                    }
                }
                key := fmt.Sprintf("%d,%d", dx2, dy2)
                slopeMap[key]++
            }

            // Now, for each line parallel to (i,j), we can form trapezoids
