                x2, y2 := points[j][0], points[j][1]
                x3, y3 := points[k][0], points[k][1]

                // Slope between i and k
                var slope1 float64
                if x3 - x1 == 0 {
                    slope1 = math.Inf(1)
                } else {
                    slope1 = float64(y3 - y1) / float64(x3 - x1)
                }

                // Slope between j and k
                var slope2 float64
                if x3 - x2 == 0 {
