                } else {
                    slope2 = float64(y3 - y2) / float64(x3 - x2)
                }

                // Check if any of these slopes match any existing pair
                // We need to find two pairs of points that share the same slope
                // So we can group points by their slope with i and j
                slopeMap[slope1]++
                slopeMap[slope2]++
            }

            // For trapezoid, we need at least two pairs of points with the same slope
            // Each pair contributes to a parallel side
            for _, v := range slopeMap {
                if v >= 2 {
                    count += int64(v * (v - 1) / 2)
                }
            }
        }
    }

    // Since each trapezoid is counted multiple times (once for each pair of parallel sides),
    // we need to adjust the count. However, the problem allows any pair of parallel sides,
    // so the initial count may overcount. A better approach is needed.

    // Alternative approach: group all pairs by their slope, then for each slope with >=2 pairs,
    // choose 2 pairs to form a trapezoid (C(m,2) where m is the number of pairs with same slope)
    // Then subtract the parallelograms (which are counted twice as trapezoids)

    // Reset count and use the better approach
    count = 0
    slopePairs := make(map[float64][][2]int)

    for i := 0; i < n; i++ {
        for j := i + 1; j < n; j++ {
            x1, y1 := points[i][0], points[i][1]
            x2, y2 := points[j][0], points[j][1]

            var slope float64
            if x2 - x1 == 0 {
                slope = math.Inf(1)
            } else {
                slope = float64(y2 - y1) / float64(x2 - x1)
            }

            slopePairs[slope] = append(slopePairs[slope], [2]int{i, j})
        }
    }

    trapezoids := int64(0)
    parallelograms := int64(0)

    for _, pairs := range slopePairs {
        m := len(pairs)
        if m >= 2 {
            trapezoids += int64(m * (m - 1) / 2)

            // Check for parallelograms: need two pairs with same slope and midpoints
            midpoints := make(map[[2]int64]int)
            for _, pair := range pairs {
                a, b := pair[0], pair[1]
                x1, y1 := points[a][0], points[a][1]
                x2, y2 := points[b][0], points[b][1]
                midX := x1 + x2
                midY := y1 + y2
                key := [2]int64{midX, midY}
                midpoints[key]++
            }

            for _, cnt := range midpoints {
                if cnt >= 2 {
                    parallelograms += int64(cnt * (cnt - 1) / 2)
                }
            }
        }
    }

    // Total trapezoids is trapezoids - parallelograms (since parallelograms are counted twice)
    return trapezoids - parallelograms
