func isTrapezoid(a, b, c, d []int64) bool {
    // Check if any two sides are parallel
    // There are 6 possible pairs of sides: ab-cd, ac-bd, ad-bc
    slopeAB := getSlopeKey(a, b)
    slopeCD := getSlopeKey(c, d)
    slopeAC := getSlopeKey(a, c)
    slopeBD := getSlopeKey(b, d)
    slopeAD := getSlopeKey(a, d)
    slopeBC := getSlopeKey(b, c)

    // Check if any pair of sides is parallel
    if slopeAB == slopeCD || slopeAC == slopeBD || slopeAD == slopeBC {
        // Ensure the four points are not colinear
        return !areColinear(a, b, c) && !areColinear(a, b, d) && !areColinear(a, c, d) && !areColinear(b, c, d)
    }
    return false
}

func getSlopeKey(a, b []int64) string {
    dx := b[0] - a[0]
    dy := b[1] - a[1]
    if dx == 0 {
        return "v"
    }
    g := gcd(dy, dx)
    return fmt.Sprintf("%d/%d", dy/g, dx/g)
}

func areColinear(a, b, c []int64) bool {
    // Area of triangle should be zero for colinear points
    area := (b[0]-a[0])*(c[1]-a[1]) - (b[1]-a[1])*(c[0]-a[0])
    return area == 0
}
