func isTrapezoid(p1, p2, p3, p4 []int64) bool {
	// Generate all 3 possible pairs of parallel sides
	// There are C(4,2)/2 = 3 ways to pair the 4 points into two pairs
	// Check each pair for parallel sides

	// Pair 1: (p1,p2) and (p3,p4)
	slope1 := getSlope(p1, p2)
	slope2 := getSlope(p3, p4)
	if (slope1 == slope2) && !isCollinear(p1, p2, p3, p4) {
