	slope1 = getSlope(p1, p3)
	slope2 = getSlope(p2, p4)
	if (slope1 == slope2) && !isCollinear(p1, p3, p2, p4) {
		return true
	}

	// Pair 3: (p1,p4) and (p2,p3)
	slope1 = getSlope(p1, p4)
	slope2 = getSlope(p2, p3)
